from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""

    from collections import defaultdict

    # Helper to join multiple items with commas and 'and'
    def join_items(items: list[str]) -> str:
        if not items:
            return ""
        if len(items) == 1:
            return items[0]
        return ", ".join(items[:-1]) + " and " + items[-1]

    # Mapping from predicate to a clause (without subject)
    # Build a map of subjects -> predicate -> objects for easy lookup
    subject_pred_map: dict[str, dict[str, list[str]]] = defaultdict(lambda: defaultdict(list))
    for t in triples:
        subject_pred_map[t.subject][t.predicate].append(t.object)

    def build_phrase(_: str, pred: str, objs: list[str]) -> str:
        # use the first object for single‑value predicates
        obj = objs[0] if objs else ""
        if pred == "birthDate":
            return f"was born on {obj}"
        if pred in ("birthYear", "birthPlace"):
            return f"was born in {obj}"
        if pred == "origin":
            return f"originates from {obj}"
        if pred == "genre":
            # simple genre statement; additional info may be appended later
            return f"has genre {obj}"
        if pred == "instrument":
            return f"plays {obj}"
        if pred == "occupation":
            return f"works as {obj}"
        if pred == "nationality":
            return f"is {obj}"
        if pred == "associatedBand/associatedMusicalArtist":
            return f"is associated with {join_items(objs)}"
        if pred == "recordLabel":
            return f"is signed to {obj}"
        if pred == "activeYearsStartYear":
            return f"started their career in {obj}"
        if pred == "activeYearsEndYear":
            return f"ended their career in {obj}"
        if pred == "deathDate":
            return f"died on {obj}"
        if pred == "deathPlace":
            return f"died in {obj}"
        if pred == "alternativeName":
            return f"is also known as {obj}"
        if pred == "stylisticOrigin":
            return f"originated from {join_items(objs)}"
        if pred == "musicFusionGenre":
            return f"has a fusion genre {join_items(objs)}"
        if pred == "derivative":
            return f"is derived from {join_items(objs)}"
        # fallback – just state the predicate and object(s)
        return f"{pred} {join_items(objs)}"

    # Build sentences per subject, ordering predicates for natural flow
    # Define a preferred order for predicates
    predicate_order = [
        "background", "occupation", "instrument", "genre", "associatedBand/associatedMusicalArtist",
        "recordLabel", "activeYearsStartYear", "activeYearsEndYear",
        "birthDate", "birthYear", "birthPlace",
        "deathDate", "deathPlace",
        "alternativeName", "stylisticOrigin", "musicFusionGenre", "derivative"
    ]

    sentences: list[str] = []

    # Helper to render a subject's information as a single sentence
    def render_subject(subj: str, pred_map: dict[str, list[str]]) -> str:
        parts: list[str] = []

        # background and occupation combine nicely
        if "background" in pred_map:
            bg = join_items(pred_map["background"])
            if "occupation" in pred_map:
                occ = join_items(pred_map["occupation"])
                parts.append(f"is a {bg} {occ}")
                pred_map.pop("occupation")
            else:
                parts.append(f"is a {bg}")

        if "occupation" in pred_map:
            occ = join_items(pred_map["occupation"])
            parts.append(f"is a {occ}")

        if "instrument" in pred_map:
            instr = join_items(pred_map["instrument"])
            parts.append(f"plays {instr}")

        if "genre" in pred_map:
            gen = join_items(pred_map["genre"])
            parts.append(f"performs {gen} music")

        if "associatedBand/associatedMusicalArtist" in pred_map:
            assoc = join_items(pred_map["associatedBand/associatedMusicalArtist"])
            parts.append(f"is associated with {assoc}")

        if "recordLabel" in pred_map:
            rl = join_items(pred_map["recordLabel"])
            parts.append(f"is signed to {rl}")

        if "activeYearsStartYear" in pred_map:
            start = join_items(pred_map["activeYearsStartYear"])
            parts.append(f"started their career in {start}")

        if "activeYearsEndYear" in pred_map:
            end = join_items(pred_map["activeYearsEndYear"])
            parts.append(f"ended their career in {end}")

        if "birthDate" in pred_map:
            bd = join_items(pred_map["birthDate"])
            parts.append(f"was born on {bd}")

        if "birthYear" in pred_map:
            by = join_items(pred_map["birthYear"])
            parts.append(f"was born in {by}")

        if "birthPlace" in pred_map:
            bp = join_items(pred_map["birthPlace"])
            parts.append(f"was born in {bp}")

        if "deathDate" in pred_map:
            dd = join_items(pred_map["deathDate"])
            parts.append(f"died on {dd}")

        if "deathPlace" in pred_map:
            dp = join_items(pred_map["deathPlace"])
            parts.append(f"died in {dp}")

        if "alternativeName" in pred_map:
            an = join_items(pred_map["alternativeName"])
            parts.append(f"is also known as {an}")

        if "stylisticOrigin" in pred_map:
            so = join_items(pred_map["stylisticOrigin"])
            parts.append(f"originated from {so}")

        if "musicFusionGenre" in pred_map:
            fg = join_items(pred_map["musicFusionGenre"])
            parts.append(f"has a fusion genre {fg}")

        if "derivative" in pred_map:
            der = join_items(pred_map["derivative"])
            parts.append(f"is derived from {der}")

        # Fallback for any remaining predicates not covered above
        for pred, objs in pred_map.items():
            if pred in predicate_order:
                continue
            parts.append(f"{pred} {join_items(objs)}")

        # Assemble the sentence
        sentence_body = join_items(parts)
        return f"{subj} {sentence_body}."

    # Iterate over each distinct subject preserving input order
    seen_subjects: set[str] = set()
    for t in triples:
        if t.subject in seen_subjects:
            continue
        seen_subjects.add(t.subject)
        pred_map = dict(subject_pred_map[t.subject])  # copy
        sentence = render_subject(t.subject, pred_map)
        # Capitalize first character
        sentence = sentence[0].upper() + sentence[1:]
        sentences.append(sentence)

    return " ".join(sentences)

# EVOLVE-BLOCK-END
